import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Electronics = () => {
  const [posts, setPosts] = useState([]);
  const [selectedPost, setSelectedPost] = useState(null);
  const [loading, setLoading] = useState(true);

  // Is URL ko check karein ki aapka backend isi port par hai
  const BASE_URL = 'http://localhost:5001';

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const res = await axios.get(`${BASE_URL}/api/blog/Electronics`);
        setPosts(res.data);
        if (res.data.length > 0) {
          setSelectedPost(res.data[0]);
        }
      } catch (err) {
        console.error("Error fetching electronics posts:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchPosts();
  }, []);

  // IMAGE FIX LOGIC: Yeh function ensure karega ki URL sahi bane
  const getImageUrl = (imagePath) => {
    if (!imagePath) return "https://via.placeholder.com/800x400?text=No+Image+Found";

    // 1. Agar full URL hai (http...) toh wahi return karo
    if (imagePath.startsWith('http')) return imagePath;

    // 2. Agar path mein 'uploads/' nahi hai aur aapka backend uploads folder use kar raha hai
    // toh aap niche line ko modify kar sakte hain. 
    const cleanPath = imagePath.startsWith('/') ? imagePath : `/${imagePath}`;

    const finalUrl = `${BASE_URL}${cleanPath}`;
    console.log("Generated Image URL:", finalUrl); // Isse console mein check karein
    return finalUrl;
  };

  if (loading) return (
    <div className="h-screen flex items-center justify-center bg-white">
      <div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
    </div>
  );

  return (
    <div className="bg-white min-h-screen">
      {/* Header */}
      <header className="pt-20 pb-10 px-6 md:px-16 bg-[#0f172a] text-white">
        <div className="max-w-7xl mx-auto">
          <span className="text-orange-500 font-black text-xs uppercase tracking-widest mb-2 block">Knowledge Base</span>
          <h1 className="text-4xl md:text-5xl font-black tracking-tighter">Electronics <span className="text-orange-500">Insights</span></h1>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 py-12">
        <div className="flex flex-col lg:flex-row gap-12">

          {/* LEFT: FULL BLOG CONTENT */}
          <div className="lg:w-2/3">
            {selectedPost ? (
              <article className="animate-fadeIn">
                <div className="rounded-[2.5rem] overflow-hidden bg-gray-100 mb-8 shadow-2xl border border-gray-100">
                  <img 
                    src={getImageUrl(selectedPost.image)} 
                    alt={selectedPost.title}
                    className="w-full h-[450px] object-cover"
                    onError={(e) => {
                      console.log("Image load failed for:", e.target.src);
                      e.target.onerror = null; 
                      e.target.src = "https://via.placeholder.com/800x450?text=Image+Not+Found+On+Server";
                    }}
                  />
                </div>

                <div className="flex items-center gap-4 mb-6">
                  <span className="px-4 py-1 bg-orange-100 text-orange-600 text-xs font-bold uppercase rounded-full">Industrial Update</span>
                  <span className="text-gray-400 text-sm">
                    {new Date(selectedPost.createdAt).toLocaleDateString('en-GB')}
                  </span>
                </div>

                <h2 className="text-4xl md:text-6xl font-black text-gray-900 mb-8 leading-[1.1] tracking-tighter">
                  {selectedPost.title}
                </h2>

                <div className="text-gray-600 text-xl leading-relaxed space-y-6 font-medium">
                  {selectedPost.description.split('\n').map((para, i) => (
                    <p key={i}>{para}</p>
                  ))}
                </div>
              </article>
            ) : (
              <div className="text-center py-20 text-gray-300">No content available.</div>
            )}
          </div>

          {/* RIGHT: STICKY LIST */}
          <div className="lg:w-1/3">
            <div className="sticky top-10 space-y-4">
              <h3 className="text-xs font-black uppercase tracking-[0.2em] text-gray-400 mb-6 border-b pb-4">Other Reports</h3>
              <div className="max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
                {posts.map((post) => (
                  <div 
                    key={post._id}
                    onClick={() => {
                      setSelectedPost(post);
                      window.scrollTo({ top: 0, behavior: 'smooth' });
                    }}
                    className={`p-5 rounded-2xl cursor-pointer transition-all duration-300 border-2 mb-4 ${
                      selectedPost?._id === post._id 
                      ? 'border-orange-500 bg-orange-50 shadow-md scale-[1.02]' 
                      : 'border-transparent hover:bg-gray-50 bg-white'
                    }`}
                  >
                    <h4 className={`font-bold leading-tight ${
                      selectedPost?._id === post._id ? 'text-orange-600' : 'text-gray-800'
                    }`}>
                      {post.title}
                    </h4>
                    <p className="text-[10px] text-gray-400 mt-2 uppercase font-bold tracking-widest">
                      {new Date(post.createdAt).toLocaleDateString()}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          </div>

        </div>
      </main>
    </div>
  );
};

export default Electronics;
